// // This module implements a 2-to-1 multiplexer where the output is inverted based on the select signal.
module top_module(
    input sel,
    input in0,
    input in1,
    output reg out
);always @ (sel or in0 or in1)
begin
    if (sel == 0)
        out = in0;
    else
        out = in1;
end

endmodule
